mapper.select:
SELECT COUNT(1)
FROM eb_frame
WHERE pid = #{pid}
  AND entid = #{entid}
  AND deleted_at IS NULL

SELECT f.id
FROM eb_frame f
WHERE f.deleted_at IS NULL
  AND f.entid = #{entid}
  AND f.id != #{frameId}
  AND (
	f.path LIKE CONCAT('%/', #{frameId}, '/%')
		OR f.path LIKE CONCAT('%/', #{frameId}, '/')
		OR f.path LIKE CONCAT('/', #{frameId}, '/%')
	)
